import { useEffect, useState } from "react";
import API from "../services/api";
import { Link } from "react-router-dom";

function Dashboard() {
  const [todaySales, setTodaySales] = useState({});
  const [totalItems, setTotalItems] = useState({});
  const [lowStock, setLowStock] = useState([]);

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    const sales = await API.get("/dashboard/today-sales");
    const items = await API.get("/dashboard/total-items-sold");
    const low = await API.get("/dashboard/low-stock");

    setTodaySales(sales.data);
    setTotalItems(items.data);
    setLowStock(low.data);
  };

  return (
    <div style={{ padding: "20px" }}>
      <h1>Dashboard</h1>

      <Link to="/inventory">Go to Inventory</Link>

      <div style={{ display: "flex", gap: "20px", marginTop: "20px" }}>
        <div style={{ border: "1px solid black", padding: "20px" }}>
          <h3>Today's Sales</h3>
          <p>Total: ₹{todaySales.total_sales_amount}</p>
          <p>Transactions: {todaySales.total_transactions}</p>
        </div>

        <div style={{ border: "1px solid black", padding: "20px" }}>
          <h3>Total Items Sold</h3>
          <p>{totalItems.total_items_sold}</p>
        </div>

        <div style={{ border: "1px solid black", padding: "20px" }}>
          <h3>Low Stock</h3>
          <p>{lowStock.length} items</p>
        </div>
      </div>
    </div>
  );
}

export default Dashboard;
